sql:
SELECT detailed_description
FROM parameter_descriptions
WHERE param_id = 1;

SELECT comment
FROM design_comments
WHERE user_id = 1;

SELECT value
FROM design_configs
WHERE design_id = 1;

SELECT COUNT(*) 
FROM design_configs 
WHERE is_default = 0;

SELECT COUNT(DISTINCT design_id) AS distinct_design_count
FROM design_configs
WHERE design_id = 0;

SELECT design_id, COUNT(*) AS comment_count
FROM design_comments
GROUP BY design_id;

SELECT param_id, item
FROM design_parameters
WHERE default_value = '100%';

external_knowledge:
- The beginning of May 2023 refers to '2023-05-01' in the date format 'YYYY-MM-DD'; 
- Design configurations and parameters are assumed to be related to specific design projects or templates; 
- The IP address from which the design modification was made is likely used for tracking or auditing purposes.
